-- backfill_prod_document_uuid.sql
-- Pobla facturas_operativas.document_uuid con los valores canonicos del backend FE.
-- Fuente: SELECT cdc, document_uuid FROM de_documents (fe_prod) — 2026-06-04.
--
-- Prerequisito: migration 0015_document_uuid.sql ya aplicada.
-- Idempotente: solo actualiza registros con document_uuid IS NULL.
--
-- Comando en VPS (produccion):
--   APP_ENV_FILE=.env.production docker compose exec -T postgres \
--     psql -U facturacion_simple -d facturacion_simple \
--     < scripts/backfill_prod_document_uuid.sql

BEGIN;

CREATE TEMP TABLE _uuid_backfill (
  cdc           TEXT PRIMARY KEY,
  document_uuid TEXT NOT NULL
) ON COMMIT DROP;

-- 67 filas — todos los documentos con cdc no nulo en fe_prod al 2026-06-04
-- (incluye APPROVED, REJECTED, CANCELLED — excluye DRAFT sin cdc)

-- Solo toca registros sin document_uuid — idempotente
UPDATE facturas_operativas fo
SET
  document_uuid = b.document_uuid,
  updated_at    = now()
FROM _uuid_backfill b
WHERE fo.cdc = b.cdc
  AND fo.document_uuid IS NULL
  AND fo.deleted_at IS NULL;

-- Verificacion: sin_uuid_con_cdc debe ser 0 antes de aprobar el deploy
SELECT
  COUNT(*)                                                           AS total_documentos,
  COUNT(*) FILTER (WHERE document_uuid IS NOT NULL)                 AS con_uuid,
  COUNT(*) FILTER (WHERE document_uuid IS NULL AND cdc IS NOT NULL) AS sin_uuid_con_cdc,
  COUNT(*) FILTER (WHERE document_uuid IS NULL AND cdc IS NULL)     AS sin_uuid_sin_cdc
FROM facturas_operativas
WHERE deleted_at IS NULL;

COMMIT;
